import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Plus, Pencil, Trash2, Music, GripVertical, Play, Pause } from "lucide-react";
import { useRef } from "react";

interface MusicTrack {
  id: string;
  title_zh: string;
  title_en: string | null;
  title_pt: string | null;
  file_url: string;
  is_active: boolean;
  sort_order: number;
  created_at: string;
}

const AdminBackgroundMusic = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingTrack, setEditingTrack] = useState<MusicTrack | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [form, setForm] = useState({
    title_zh: "",
    title_en: "",
    title_pt: "",
    file_url: "",
  });

  const { data: tracks = [], isLoading } = useQuery({
    queryKey: ["background-music-admin"],
    queryFn: async () => {
      // Admin needs to see all tracks including inactive ones
      const { data, error } = await supabase
        .from("background_music")
        .select("*")
        .order("sort_order", { ascending: true });
      if (error) throw error;
      return data as MusicTrack[];
    },
  });

  const saveMutation = useMutation({
    mutationFn: async (values: typeof form & { id?: string }) => {
      if (values.id) {
        const { error } = await supabase
          .from("background_music")
          .update({
            title_zh: values.title_zh,
            title_en: values.title_en || null,
            title_pt: values.title_pt || null,
            file_url: values.file_url,
            updated_at: new Date().toISOString(),
          })
          .eq("id", values.id);
        if (error) throw error;
      } else {
        const maxOrder = tracks.length > 0 ? Math.max(...tracks.map(t => t.sort_order)) + 1 : 1;
        const { error } = await supabase
          .from("background_music")
          .insert({
            title_zh: values.title_zh,
            title_en: values.title_en || null,
            title_pt: values.title_pt || null,
            file_url: values.file_url,
            sort_order: maxOrder,
          });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["background-music-admin"] });
      queryClient.invalidateQueries({ queryKey: ["background-music"] });
      setDialogOpen(false);
      setEditingTrack(null);
      toast.success(t("common.saved", "已保存"));
    },
    onError: (err: any) => toast.error(err.message),
  });

  const toggleMutation = useMutation({
    mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
      const { error } = await supabase
        .from("background_music")
        .update({ is_active, updated_at: new Date().toISOString() })
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["background-music-admin"] });
      queryClient.invalidateQueries({ queryKey: ["background-music"] });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("background_music").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["background-music-admin"] });
      queryClient.invalidateQueries({ queryKey: ["background-music"] });
      setDeleteConfirm(null);
      toast.success(t("common.deleted", "已删除"));
    },
  });

  const openCreate = () => {
    setEditingTrack(null);
    setForm({ title_zh: "", title_en: "", title_pt: "", file_url: "" });
    setDialogOpen(true);
  };

  const openEdit = (track: MusicTrack) => {
    setEditingTrack(track);
    setForm({
      title_zh: track.title_zh,
      title_en: track.title_en || "",
      title_pt: track.title_pt || "",
      file_url: track.file_url,
    });
    setDialogOpen(true);
  };

  const handleSave = () => {
    if (!form.title_zh || !form.file_url) {
      toast.error("请填写中文名称和音乐链接");
      return;
    }
    saveMutation.mutate({ ...form, id: editingTrack?.id });
  };

  const togglePlay = (track: MusicTrack) => {
    if (playingId === track.id) {
      audioRef.current?.pause();
      audioRef.current = null;
      setPlayingId(null);
    } else {
      audioRef.current?.pause();
      const audio = new Audio(track.file_url);
      audio.volume = 0.3;
      audio.play().catch(() => {});
      audio.onended = () => setPlayingId(null);
      audioRef.current = audio;
      setPlayingId(track.id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Music className="h-6 w-6" />
          <h1 className="text-2xl font-bold">{t("admin.backgroundMusic.title", "背景音乐管理")}</h1>
        </div>
        <Button onClick={openCreate}>
          <Plus className="h-4 w-4 mr-2" />
          {t("admin.backgroundMusic.add", "添加音乐")}
        </Button>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-12">#</TableHead>
                <TableHead>{t("admin.backgroundMusic.nameZh", "中文名称")}</TableHead>
                <TableHead>{t("admin.backgroundMusic.nameEn", "英文名称")}</TableHead>
                <TableHead>{t("admin.backgroundMusic.url", "音乐链接")}</TableHead>
                <TableHead className="w-20">{t("common.status", "状态")}</TableHead>
                <TableHead className="w-32">{t("common.actions", "操作")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                <TableRow>
                  <TableCell colSpan={6} className="text-center py-8 text-muted-foreground">
                    {t("common.loading", "加载中...")}
                  </TableCell>
                </TableRow>
              ) : tracks.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} className="text-center py-8 text-muted-foreground">
                    {t("admin.backgroundMusic.empty", "暂无音乐")}
                  </TableCell>
                </TableRow>
              ) : (
                tracks.map((track, index) => (
                  <TableRow key={track.id}>
                    <TableCell>{index + 1}</TableCell>
                    <TableCell className="font-medium">{track.title_zh}</TableCell>
                    <TableCell className="text-muted-foreground">{track.title_en || "-"}</TableCell>
                    <TableCell className="max-w-[200px] truncate text-xs text-muted-foreground">
                      {track.file_url}
                    </TableCell>
                    <TableCell>
                      <Switch
                        checked={track.is_active}
                        onCheckedChange={(checked) =>
                          toggleMutation.mutate({ id: track.id, is_active: checked })
                        }
                      />
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => togglePlay(track)}
                        >
                          {playingId === track.id ? (
                            <Pause className="h-4 w-4" />
                          ) : (
                            <Play className="h-4 w-4" />
                          )}
                        </Button>
                        <Button variant="ghost" size="icon" onClick={() => openEdit(track)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="text-destructive"
                          onClick={() => setDeleteConfirm(track.id)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingTrack
                ? t("admin.backgroundMusic.edit", "编辑音乐")
                : t("admin.backgroundMusic.add", "添加音乐")}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>{t("admin.backgroundMusic.nameZh", "中文名称")} *</Label>
              <Input
                value={form.title_zh}
                onChange={(e) => setForm({ ...form, title_zh: e.target.value })}
                placeholder="例如：轻松钢琴曲"
              />
            </div>
            <div>
              <Label>{t("admin.backgroundMusic.nameEn", "英文名称")}</Label>
              <Input
                value={form.title_en}
                onChange={(e) => setForm({ ...form, title_en: e.target.value })}
                placeholder="e.g. Relaxing Piano"
              />
            </div>
            <div>
              <Label>{t("admin.backgroundMusic.namePt", "葡文名称")}</Label>
              <Input
                value={form.title_pt}
                onChange={(e) => setForm({ ...form, title_pt: e.target.value })}
                placeholder="ex. Piano Relaxante"
              />
            </div>
            <div>
              <Label>{t("admin.backgroundMusic.url", "音乐链接")} *</Label>
              <Input
                value={form.file_url}
                onChange={(e) => setForm({ ...form, file_url: e.target.value })}
                placeholder="/music/track.mp3 或 https://..."
              />
              <p className="text-xs text-muted-foreground mt-1">
                支持本地路径（如 /music/track.mp3）或外部URL
              </p>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              {t("common.cancel", "取消")}
            </Button>
            <Button onClick={handleSave} disabled={saveMutation.isPending}>
              {t("common.save", "保存")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirm Dialog */}
      <Dialog open={!!deleteConfirm} onOpenChange={() => setDeleteConfirm(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("common.confirmDelete", "确认删除")}</DialogTitle>
          </DialogHeader>
          <p>{t("admin.backgroundMusic.deleteConfirm", "确定要删除这首音乐吗？")}</p>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteConfirm(null)}>
              {t("common.cancel", "取消")}
            </Button>
            <Button
              variant="destructive"
              onClick={() => deleteConfirm && deleteMutation.mutate(deleteConfirm)}
              disabled={deleteMutation.isPending}
            >
              {t("common.delete", "删除")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminBackgroundMusic;
